import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  AreaChart,
  Area,
  ComposedChart,
  Bar
} from 'recharts';
import toast from 'react-hot-toast';
import { 
  FiArrowLeft, FiTrendingUp, FiTrendingDown, FiActivity, 
  FiDollarSign, FiClock, FiZap, FiStar, FiAward, FiShield,
  FiAlertCircle, FiCheckCircle, FiInfo, FiExternalLink,
  FiBarChart2, FiCalendar, FiPercent, FiShoppingBag
} from 'react-icons/fi';

const API_URL = 'http://localhost:5000/api';

function ProductDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => {
    fetchProductDetails();
    const interval = setInterval(fetchProductDetails, 60000);
    return () => clearInterval(interval);
  }, [id]);

  const fetchProductDetails = async () => {
    setLoading(true);
    try {
      const response = await axios.get(`${API_URL}/products/${id}`, {
        withCredentials: true
      });
      setProduct(response.data);
    } catch (error) {
      console.error('Error:', error);
      setError('Failed to load product details');
      toast.error('Failed to load product details');
    } finally {
      setLoading(false);
    }
  };

  const getDecisionConfig = (decision) => {
    switch(decision) {
      case 'BUY_NOW':
        return {
          title: 'BUY NOW',
          icon: <FiZap size={24} />,
          gradient: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          color: '#10b981',
          bg: 'rgba(16, 185, 129, 0.1)',
          message: 'Perfect time to purchase!'
        };
      case 'BUY_SOON':
        return {
          title: 'BUY BEFORE INCREASE',
          icon: <FiClock size={24} />,
          gradient: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
          color: '#f59e0b',
          bg: 'rgba(245, 158, 11, 0.1)',
          message: 'Price may increase soon!'
        };
      default:
        return {
          title: 'WAIT',
          icon: <FiTrendingDown size={24} />,
          gradient: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
          color: '#ef4444',
          bg: 'rgba(239, 68, 68, 0.1)',
          message: 'Better deals coming soon'
        };
    }
  };

  if (loading) {
    return (
      <div style={styles.loadingContainer}>
        <div style={styles.loadingSpinner}></div>
        <p style={styles.loadingText}>Loading product insights...</p>
      </div>
    );
  }

  if (error || !product) {
    return (
      <div style={styles.errorContainer}>
        <FiAlertCircle size={64} color="#ef4444" />
        <h2 style={styles.errorTitle}>Oops! Something went wrong</h2>
        <p style={styles.errorText}>{error || 'Product not found'}</p>
        <button style={styles.errorButton} onClick={() => navigate('/dashboard')}>
          Back to Dashboard
        </button>
      </div>
    );
  }

  const decisionConfig = getDecisionConfig(product.recommendation?.decision);
  const discount = product.discount_info?.discount_percentage || 0;
  const savings = product.original_price && product.current_price 
    ? (product.original_price - product.current_price).toFixed(2) 
    : 0;

  // Prepare chart data
  const historyData = product.price_history?.map(item => ({
    date: new Date(item.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
    price: item.price,
    fullDate: new Date(item.date)
  })) || [];

  const predictionData = product.predictions?.dates?.map((date, idx) => ({
    date: new Date(date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
    price: product.predictions.prices[idx],
    isPrediction: true
  })) || [];

  const allData = [...historyData.slice(-20), ...predictionData];

  return (
    <div style={styles.container}>
      {/* Animated Background */}
      <div style={styles.animatedBg}>
        <div style={styles.glowOrb1}></div>
        <div style={styles.glowOrb2}></div>
        <div style={styles.glowOrb3}></div>
      </div>

      {/* Header */}
      <div style={styles.header}>
        <button style={styles.backButton} onClick={() => navigate('/dashboard')}>
          <FiArrowLeft size={20} />
          <span>Back to Dashboard</span>
        </button>
        <div style={styles.headerActions}>
          {product.url && (
            <a href={product.url} target="_blank" rel="noopener noreferrer" style={styles.externalLink}>
              <FiExternalLink size={18} />
              <span>View on Store</span>
            </a>
          )}
        </div>
      </div>

      {/* Main Content */}
      <div style={styles.mainContent}>
        {/* Product Title Section */}
        <div style={styles.titleSection}>
          <h1 style={styles.productTitle}>{product.name}</h1>
          <div style={styles.productId}>Product ID: {product.id}</div>
        </div>

        {/* Recommendation Card */}
        <div style={{...styles.recommendationCard, background: decisionConfig.gradient}}>
          <div style={styles.recommendationIcon}>{decisionConfig.icon}</div>
          <div style={styles.recommendationContent}>
            <div style={styles.recommendationLabel}>AI Recommendation</div>
            <div style={styles.recommendationTitle}>{decisionConfig.title}</div>
            <div style={styles.recommendationMessage}>{decisionConfig.message}</div>
          </div>
          <div style={styles.confidenceBadge}>
            <div style={styles.confidenceCircle}>
              <span style={styles.confidenceValue}>{product.recommendation?.confidence || 0}%</span>
              <span style={styles.confidenceLabel}>confidence</span>
            </div>
          </div>
        </div>

        {/* Stats Grid */}
        <div style={styles.statsGrid}>
          <div style={styles.statCard}>
            <div style={styles.statIcon}><FiDollarSign size={24} color="#10b981" /></div>
            <div style={styles.statContent}>
              <div style={styles.statLabel}>Current Price</div>
              <div style={styles.statValue}>${product.current_price?.toFixed(2)}</div>
              {product.original_price && (
                <div style={styles.statOldPrice}>${product.original_price?.toFixed(2)}</div>
              )}
            </div>
          </div>

          <div style={styles.statCard}>
            <div style={styles.statIcon}><FiPercent size={24} color="#f59e0b" /></div>
            <div style={styles.statContent}>
              <div style={styles.statLabel}>Discount</div>
              <div style={styles.statValue}>{discount}% OFF</div>
              {savings > 0 && (
                <div style={styles.statSavings}>Save ${savings}</div>
              )}
            </div>
          </div>

          <div style={styles.statCard}>
            <div style={styles.statIcon}><FiActivity size={24} color="#667eea" /></div>
            <div style={styles.statContent}>
              <div style={styles.statLabel}>Price Trend</div>
              <div style={styles.statValue}>
                {product.predictions?.trend === 'upward' && <><FiTrendingUp /> Rising</>}
                {product.predictions?.trend === 'downward' && <><FiTrendingDown /> Falling</>}
                {product.predictions?.trend === 'stable' && <>Stable</>}
              </div>
              <div style={styles.statSubtext}>Next 7 days</div>
            </div>
          </div>

          <div style={styles.statCard}>
            <div style={styles.statIcon}><FiStar size={24} color="#f59e0b" /></div>
            <div style={styles.statContent}>
              <div style={styles.statLabel}>Seller Action</div>
              <div style={styles.statValue}>
                {product.seller_insights?.next_move_prediction || 'Analyzing...'}
              </div>
              <div style={styles.statSubtext}>Predicted move</div>
            </div>
          </div>
        </div>

        {/* Tab Navigation */}
        <div style={styles.tabNav}>
          <button 
            style={{...styles.tabButton, ...(activeTab === 'overview' ? styles.tabActive : {})}}
            onClick={() => setActiveTab('overview')}
          >
            <FiBarChart2 /> Overview
          </button>
          <button 
            style={{...styles.tabButton, ...(activeTab === 'analysis' ? styles.tabActive : {})}}
            onClick={() => setActiveTab('analysis')}
          >
            <FiActivity /> Analysis
          </button>
          <button 
            style={{...styles.tabButton, ...(activeTab === 'insights' ? styles.tabActive : {})}}
            onClick={() => setActiveTab('insights')}
          >
            <FiInfo /> Insights
          </button>
        </div>

        {/* Tab Content */}
        <div style={styles.tabContent}>
          {activeTab === 'overview' && (
            <>
              {/* Price Chart */}
              <div style={styles.chartCard}>
                <div style={styles.chartHeader}>
                  <h3 style={styles.chartTitle}>Price History & Prediction</h3>
                  <div style={styles.chartLegend}>
                    <span><span style={{background: '#10b981'}}></span> Historical</span>
                    <span><span style={{background: '#f59e0b'}}></span> Predicted</span>
                  </div>
                </div>
                <ResponsiveContainer width="100%" height={400}>
                  <ComposedChart data={allData}>
                    <defs>
                      <linearGradient id="priceGradient" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.1)" />
                    <XAxis dataKey="date" stroke="#a0aec0" />
                    <YAxis stroke="#a0aec0" />
                    <Tooltip 
                      contentStyle={{ background: '#1e1e2e', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '8px' }}
                      labelStyle={{ color: '#fff' }}
                    />
                    <Legend />
                    <Area type="monotone" dataKey="price" stroke="#10b981" fill="url(#priceGradient)" name="Price" />
                    <Bar dataKey="isPrediction" fill="#f59e0b" name="Prediction" />
                  </ComposedChart>
                </ResponsiveContainer>
                <div style={styles.chartFooter}>
                  <FiCalendar size={14} />
                  <span>Last 30 days history + 7 days forecast</span>
                </div>
              </div>

              {/* Reasoning Section */}
              <div style={styles.reasoningCard}>
                <div style={styles.reasoningHeader}>
                  <FiInfo size={20} color="#667eea" />
                  <h3>Why this recommendation?</h3>
                </div>
                <p style={styles.reasoningText}>{product.recommendation?.reasoning}</p>
              </div>
            </>
          )}

          {activeTab === 'analysis' && (
            <>
              <div style={styles.analysisGrid}>
                <div style={styles.analysisCard}>
                  <div style={styles.analysisIcon}><FiShield size={28} color="#10b981" /></div>
                  <h4>Discount Authenticity</h4>
                  <div style={styles.analysisStatus}>
                    {product.discount_info?.is_genuine ? (
                      <><FiCheckCircle color="#10b981" /> Genuine Discount</>
                    ) : (
                      <><FiAlertCircle color="#ef4444" /> Fake Discount Warning</>
                    )}
                  </div>
                  <p style={styles.analysisText}>{product.discount_info?.message}</p>
                </div>

                <div style={styles.analysisCard}>
                  <div style={styles.analysisIcon}><FiTrendingUp size={28} color="#667eea" /></div>
                  <h4>Seller Strategy</h4>
                  <div style={styles.analysisStatus}>
                    Confidence: {product.seller_insights?.confidence}%
                  </div>
                  <p style={styles.analysisText}>{product.seller_insights?.message}</p>
                  {product.seller_insights?.patterns?.map((pattern, i) => (
                    <div key={i} style={styles.patternBadge}>{pattern}</div>
                  ))}
                </div>

                <div style={styles.analysisCard}>
                  <div style={styles.analysisIcon}><FiAward size={28} color="#f59e0b" /></div>
                  <h4>Price Analysis</h4>
                  <div style={styles.analysisStats}>
                    <div>30-Day High: ${Math.max(...(product.price_history?.map(p => p.price) || [0])).toFixed(2)}</div>
                    <div>30-Day Low: ${Math.min(...(product.price_history?.map(p => p.price) || [0])).toFixed(2)}</div>
                    <div>Average: ${(product.price_history?.reduce((a,b) => a + b.price, 0) / (product.price_history?.length || 1)).toFixed(2)}</div>
                  </div>
                </div>
              </div>
            </>
          )}

          {activeTab === 'insights' && (
            <div style={styles.insightsContainer}>
              <div style={styles.insightCard}>
                <div style={styles.insightIcon}>💰</div>
                <div>
                  <h4>Best Time to Buy</h4>
                  <p>Based on historical patterns, prices typically drop during weekends. Consider waiting for Saturday/Sunday.</p>
                </div>
              </div>
              <div style={styles.insightCard}>
                <div style={styles.insightIcon}>📊</div>
                <div>
                  <h4>Price Volatility</h4>
                  <p>This product shows moderate price fluctuations. Setting up price alerts can help catch the best deals.</p>
                </div>
              </div>
              <div style={styles.insightCard}>
                <div style={styles.insightIcon}>🎯</div>
                <div>
                  <h4>Target Price</h4>
                  <p>Historical lowest price was ${Math.min(...(product.price_history?.map(p => p.price) || [0])).toFixed(2)}. 
                  Current price is {((product.current_price - Math.min(...(product.price_history?.map(p => p.price) || [0]))) / Math.min(...(product.price_history?.map(p => p.price) || [1])) * 100).toFixed(0)}% above lowest.</p>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
        
        @keyframes float {
          0%, 100% { transform: translate(0, 0); }
          50% { transform: translate(20px, -20px); }
        }
        
        @keyframes pulse {
          0%, 100% { opacity: 0.6; }
          50% { opacity: 1; }
        }
      `}</style>
    </div>
  );
}

const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #0f0c29 0%, #302b63 50%, #24243e 100%)',
    padding: '20px',
    position: 'relative',
    overflowX: 'hidden',
  },
  animatedBg: {
    position: 'fixed',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
    zIndex: 0,
    overflow: 'hidden',
  },
  glowOrb1: {
    position: 'absolute',
    width: '400px',
    height: '400px',
    background: 'radial-gradient(circle, rgba(102,126,234,0.3) 0%, transparent 70%)',
    borderRadius: '50%',
    top: '-100px',
    left: '-100px',
    animation: 'float 15s infinite ease-in-out',
  },
  glowOrb2: {
    position: 'absolute',
    width: '500px',
    height: '500px',
    background: 'radial-gradient(circle, rgba(245,87,108,0.2) 0%, transparent 70%)',
    borderRadius: '50%',
    bottom: '-150px',
    right: '-150px',
    animation: 'float 20s infinite ease-in-out reverse',
  },
  glowOrb3: {
    position: 'absolute',
    width: '300px',
    height: '300px',
    background: 'radial-gradient(circle, rgba(79,172,254,0.2) 0%, transparent 70%)',
    borderRadius: '50%',
    top: '50%',
    left: '50%',
    transform: 'translate(-50%, -50%)',
    animation: 'pulse 8s infinite ease-in-out',
  },
  loadingContainer: {
    minHeight: '100vh',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    background: 'linear-gradient(135deg, #0f0c29 0%, #302b63 50%, #24243e 100%)',
  },
  loadingSpinner: {
    width: '50px',
    height: '50px',
    border: '3px solid rgba(102,126,234,0.3)',
    borderTop: '3px solid #667eea',
    borderRadius: '50%',
    animation: 'spin 1s linear infinite',
  },
  loadingText: {
    marginTop: '20px',
    color: '#a0aec0',
  },
  errorContainer: {
    minHeight: '100vh',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    background: 'linear-gradient(135deg, #0f0c29 0%, #302b63 50%, #24243e 100%)',
    textAlign: 'center',
    padding: '20px',
  },
  errorTitle: {
    fontSize: '24px',
    color: '#fff',
    marginTop: '20px',
  },
  errorText: {
    color: '#a0aec0',
    marginTop: '10px',
  },
  errorButton: {
    marginTop: '20px',
    background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
    color: 'white',
    border: 'none',
    padding: '12px 24px',
    borderRadius: '12px',
    cursor: 'pointer',
  },
  header: {
    position: 'relative',
    zIndex: 2,
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '30px',
    flexWrap: 'wrap',
    gap: '15px',
  },
  backButton: {
    background: 'rgba(255,255,255,0.1)',
    border: '1px solid rgba(255,255,255,0.2)',
    padding: '10px 20px',
    borderRadius: '12px',
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
    color: '#fff',
    cursor: 'pointer',
    transition: 'all 0.3s',
  },
  externalLink: {
    background: 'rgba(255,255,255,0.1)',
    border: '1px solid rgba(255,255,255,0.2)',
    padding: '10px 20px',
    borderRadius: '12px',
    display: 'flex',
    alignItems: 'center',
    gap: '8px',
    color: '#fff',
    textDecoration: 'none',
    transition: 'all 0.3s',
  },
  mainContent: {
    position: 'relative',
    zIndex: 2,
    maxWidth: '1400px',
    margin: '0 auto',
  },
  titleSection: {
    marginBottom: '30px',
  },
  productTitle: {
    fontSize: '28px',
    fontWeight: '700',
    color: '#fff',
    marginBottom: '8px',
  },
  productId: {
    fontSize: '12px',
    color: '#a0aec0',
  },
  recommendationCard: {
    borderRadius: '20px',
    padding: '30px',
    marginBottom: '30px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    flexWrap: 'wrap',
    gap: '20px',
    boxShadow: '0 20px 40px rgba(0,0,0,0.3)',
  },
  recommendationIcon: {
    width: '60px',
    height: '60px',
    background: 'rgba(255,255,255,0.2)',
    borderRadius: '30px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
  },
  recommendationContent: {
    flex: 1,
  },
  recommendationLabel: {
    fontSize: '12px',
    opacity: 0.8,
    marginBottom: '5px',
  },
  recommendationTitle: {
    fontSize: '28px',
    fontWeight: '700',
    marginBottom: '5px',
  },
  recommendationMessage: {
    fontSize: '14px',
    opacity: 0.9,
  },
